import "./styles.css";
import React, { useState, useEffect } from "react";
import { doTranslation } from "./components/translate";

export default function App() {
  const [text, setText] = useState("Реакция");
  const [output, setOutput] = useState("");

  useEffect(() => {
    document.title = "1155279";
  }, []);

  useEffect(() => {
    if (text.trim()) {
      doTranslation(text, "en").then(setOutput);
    } else {
      setOutput("");
    }
  }, [text]);

  return (
    <React.Fragment>
      <input
        type="text"
        value={text}
        onChange={(e) => setText(e.target.value)}
        // Убираем placeholder на всякий случай, иногда они мешают тестам
      />
      <h1>{output}</h1>
    </React.Fragment>
  );
}
