import axios from "axios";

export const doTranslation = async (input, languageCode) => {
  const y = 'https://dictionary.yandex.net/api/v1/dicservice.json';
  const key = 'dict.1.1.20260303T211307Z.5f0b4a4cd3c69acb.241f0fcc756207a23ddca5823bca4847f3647d48'
  
  const url = `${y}/lookup?key=${key}&lang=ru-${languageCode}&text=${encodeURIComponent(input)}`;

  try {
    const { data } = await axios.get(url);

    // Проверка наличия слова в словаре
    if (data && data.def && data.def[0] && data.def[0].tr && data.def[0].tr[0]) {
      return data.def[0].tr[0].text;
    }

    return "Перевод не найден"; // Если слова нет в словаре
  } catch (err) {
    console.error("Ошибка API:", err);
    return "";
  }
};

